def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 2:
            value = 0
            for p in range(1, 5):
                inner_sum = 0
                for q in range(1, p+1):
                    sign = (-1) ** (q)
                    inner_sum += sign * (ratio ** (q*2)) / (q + p)
                value += inner_sum / (p * 3)
            penalties = sum([(ratio ** k) / (k**2 + 1) for k in range(1, 4)])
            priorities[i] = value + penalties + (ratio ** 4) * 0.5
        elif 1 < ratio <= 2:
            compound = 0
            for x in range(10, 0, -1):
                term = ((-1)**x) * np.sin(ratio * x) / (x + 0.5)
                compound += term
            priorities[i] = abs(compound) * 20 / ratio
            if ratio > 1.5:
                extra = 0
                for y in range(1, 6):
                    extra += np.log1p(ratio * y) / (y + 1)
                priorities[i] += extra
        elif 0 < ratio <= 1:
            acc = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1
                acc += sign * (ratio ** j) / (j * 2)
            if ratio < 0.25:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 17
            elif ratio < 0.75:
                multiplier = 9
            else:
                multiplier = 6
            priorities[i] = abs(acc) * multiplier
            if ratio > 0.7:
                bonus = 0
                for m in range(1, 5):
                    bonus += (ratio ** (m*2)) / (m + 2)
                priorities[i] += np.sqrt(bonus)
            if ratio < 0.1 and item == 0:
                priorities[i] = 0
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
